// Compliant: Separate controllers for movies and photos
[ApiController]
[Route("api/movies")]
public class MoviesController : ControllerBase
{
    [HttpGet]
    public IActionResult GetMovies() => Ok();

    [HttpPost]
    public IActionResult CreateMovie(Movie movie) => Created();
}

[ApiController]
[Route("api/photos")]
public class PhotosController : ControllerBase
{
    [HttpGet]
    public IActionResult GetPhotos() => Ok();

    [HttpPost]
    public IActionResult UploadPhoto(Photo photo) => Created();
}
